# Generated by Kiro using Auto, reviewed by ccharland
BeforeAll {
    $script:ScriptPath = "$PSScriptRoot/../Scripts/Test-ManifestCompliance.ps1"
}

Describe 'Test-ManifestCompliance' {

    BeforeAll {
        $script:TestRoot = Join-Path ([System.IO.Path]::GetTempPath()) "ManifestComplianceTests_$([guid]::NewGuid().ToString('N'))"
        New-Item -ItemType Directory -Path $script:TestRoot -Force | Out-Null
    }

    AfterAll {
        if (Test-Path $script:TestRoot) {
            Remove-Item -Recurse -Force $script:TestRoot
        }
    }

    Context 'Path validation' {

        It 'Throws when manifest path does not exist' {
            $publicDir = Join-Path $script:TestRoot 'Public'
            New-Item -ItemType Directory -Path $publicDir -Force | Out-Null

            { & $script:ScriptPath -ManifestPath 'C:\NonExistent\Fake.psd1' -PublicPath $publicDir } |
            Should -Throw '*Module manifest not found*'
        }

        It 'Throws when public source directory does not exist' {
            $manifestPath = Join-Path $script:TestRoot 'Test.psd1'
            Set-Content -Path $manifestPath -Value "@{ FunctionsToExport = @() }"

            { & $script:ScriptPath -ManifestPath $manifestPath -PublicPath 'C:\NonExistent\Public' } |
            Should -Throw '*Public source directory not found*'
        }
    }

    Context 'Manifest and source are in sync' {

        BeforeAll {
            $script:SyncDir = Join-Path $script:TestRoot 'SyncTest'
            $script:SyncPublic = Join-Path $script:SyncDir 'Public'
            New-Item -ItemType Directory -Path $script:SyncPublic -Force | Out-Null

            # Create a .ps1 with a function definition
            $functionContent = @'
function Get-SyncedItem {
    [CmdletBinding()]
    param()
    return 'synced'
}
'@
            Set-Content -Path (Join-Path $script:SyncPublic 'Get-SyncedItem.ps1') -Value $functionContent

            # Create matching manifest
            $script:SyncManifest = Join-Path $script:SyncDir 'Test.psd1'
            Set-Content -Path $script:SyncManifest -Value "@{ FunctionsToExport = @('Get-SyncedItem') }"
        }

        It 'Passes when FunctionsToExport matches discovered functions' {
            { & $script:ScriptPath -ManifestPath $script:SyncManifest -PublicPath $script:SyncPublic } |
            Should -Not -Throw
        }
    }

    Context 'Function defined in source but missing from manifest' {

        BeforeAll {
            $script:MissingExportDir = Join-Path $script:TestRoot 'MissingExport'
            $script:MissingExportPublic = Join-Path $script:MissingExportDir 'Public'
            New-Item -ItemType Directory -Path $script:MissingExportPublic -Force | Out-Null

            # Two functions in source
            $functionContent = @'
function Get-ExportedItem {
    [CmdletBinding()]
    param()
}

function Get-ForgottenItem {
    [CmdletBinding()]
    param()
}
'@
            Set-Content -Path (Join-Path $script:MissingExportPublic 'Functions.ps1') -Value $functionContent

            # Manifest only lists one
            $script:MissingExportManifest = Join-Path $script:MissingExportDir 'Test.psd1'
            Set-Content -Path $script:MissingExportManifest -Value "@{ FunctionsToExport = @('Get-ExportedItem') }"
        }

        It 'Throws when a function is defined but not exported' {
            { & $script:ScriptPath -ManifestPath $script:MissingExportManifest -PublicPath $script:MissingExportPublic } |
            Should -Throw '*does not match the public function surface*'
        }
    }

    Context 'Function in manifest but not in source (stale export)' {

        BeforeAll {
            $script:StaleDir = Join-Path $script:TestRoot 'StaleExport'
            $script:StalePublic = Join-Path $script:StaleDir 'Public'
            New-Item -ItemType Directory -Path $script:StalePublic -Force | Out-Null

            # One function in source
            $functionContent = @'
function Get-RealItem {
    [CmdletBinding()]
    param()
}
'@
            Set-Content -Path (Join-Path $script:StalePublic 'Get-RealItem.ps1') -Value $functionContent

            # Manifest lists the real one plus a stale one
            $script:StaleManifest = Join-Path $script:StaleDir 'Test.psd1'
            Set-Content -Path $script:StaleManifest -Value "@{ FunctionsToExport = @('Get-RealItem', 'Get-DeletedItem') }"
        }

        It 'Throws when a function is exported but not defined in source' {
            { & $script:ScriptPath -ManifestPath $script:StaleManifest -PublicPath $script:StalePublic } |
            Should -Throw '*does not match the public function surface*'
        }
    }

    Context 'Functions in nested .psm1 files are discovered' {

        BeforeAll {
            $script:NestedDir = Join-Path $script:TestRoot 'NestedModule'
            $script:NestedPublic = Join-Path $script:NestedDir 'Public'
            $script:NestedSub = Join-Path $script:NestedPublic 'SubModule'
            New-Item -ItemType Directory -Path $script:NestedSub -Force | Out-Null

            # Function in a nested .psm1
            $psmContent = @'
function Get-NestedItem {
    [CmdletBinding()]
    param()
}
'@
            Set-Content -Path (Join-Path $script:NestedSub 'SubModule.psm1') -Value $psmContent

            # Manifest exports it
            $script:NestedManifest = Join-Path $script:NestedDir 'Test.psd1'
            Set-Content -Path $script:NestedManifest -Value "@{ FunctionsToExport = @('Get-NestedItem') }"
        }

        It 'Passes when functions in nested .psm1 files match the manifest' {
            { & $script:ScriptPath -ManifestPath $script:NestedManifest -PublicPath $script:NestedPublic } |
            Should -Not -Throw
        }
    }

    Context 'Empty manifest with empty source passes' {

        BeforeAll {
            $script:EmptyDir = Join-Path $script:TestRoot 'EmptyTest'
            $script:EmptyPublic = Join-Path $script:EmptyDir 'Public'
            New-Item -ItemType Directory -Path $script:EmptyPublic -Force | Out-Null

            $script:EmptyManifest = Join-Path $script:EmptyDir 'Test.psd1'
            Set-Content -Path $script:EmptyManifest -Value "@{ FunctionsToExport = @() }"
        }

        It 'Passes with no exported functions and no source functions' {
            { & $script:ScriptPath -ManifestPath $script:EmptyManifest -PublicPath $script:EmptyPublic } |
            Should -Not -Throw
        }
    }
}
